370→/// Generate an Error value.
371→fn generate_error(
372→    metadata: &serde_json::Map<String, serde_json::Value>,
373→    rng: &mut impl Rng,
374→) -> Value {
375→    let class = metadata
376→        .get("class")
377→        .and_then(|c| c.as_str())
378→        .unwrap_or_else(|| {
379→            let classes = ["Error", "TypeError", "RangeError", "SyntaxError"];
380→            classes[rng.random_range(0..classes.len())]
381→        });
382→    let messages = ["", "oops", "invalid argument", "out of range", "unexpected token"];
383→    let msg = messages[rng.random_range(0..messages.len())];
384→    json!({"__complex_type": "error", "class": class, "message": msg})
385→}
