 946→/// Batch-prefetch values from custom generators via the frontend protocol.
 947→///
 948→/// Sends `Generate` commands for each unique generator and stores the returned
 949→/// values in a `PrefetchedValues` store. Each generator is called `count` times.
 950→///
 951→/// Returns an error if any protocol send/receive fails.
 952→pub async fn prefetch_custom_values(
 953→    sources: &[ValueSource],
 954→    frontend: &mut crate::frontend::Frontend,
 955→    count: usize,
 956→) -> Result<PrefetchedValues, crate::frontend::FrontendError> {
 957→    let commands = collect_generate_commands(sources);
 958→    let mut store = PrefetchedValues::new();
 959→
 960→    for (file, name, kind) in &commands {
 961→        for _ in 0..count {
 962→            let response = frontend
 963→                .send(crate::protocol::Command::Generate {
 964→                    file: file.clone(),
 965→                    name: name.clone(),
 966→                    kind: kind.clone(),
 967→                    recipe: None,
 968→                    project_root: None,
 969→                })
 970→                .await?;
 971→
 972→            match response.result {
 973→                crate::protocol::ResponseResult::Generate { value, generator_id, recipe } => {
 974→                    let effective_recipe = recipe.as_ref().unwrap_or(&value);
 975→                    let composite = crate::canonical_json::composite_id(&generator_id, effective_recipe);
 976→                    store.insert_entry(file.clone(), name.clone(), GeneratedEntry {
 977→                        value,
 978→                        generator_id,
 979→                        recipe,
 980→                        composite_id: composite,
 981→                    });
 982→                }
 983→                crate::protocol::ResponseResult::Error { message, .. } => {
 984→                    // Log but don't fail -- we'll fall back to built-in generation.
 985→                    log::warn!("generator error for {name} ({file}): {message}");
 986→                }
 987→                _ => {
 988→                    // Unexpected response type -- skip this generator.
 989→                    log::warn!("unexpected response for generator {name}");
 990→                }
 991→            }
 992→        }
 993→    }
 994→
 995→    Ok(store)
 996→}
