1448→/// Field-level crossover for objects: each field independently chosen from A or B.
1449→fn crossover_object(
1450→    a: &Value,
1451→    b: &Value,
1452→    fields: &[(String, TypeInfo)],
1453→    rng: &mut impl Rng,
1454→) -> (Value, Value) {
1455→    let obj_a = a.as_object();
1456→    let obj_b = b.as_object();
1457→
1458→    // If either isn't actually an object, fall back to uniform swap
1459→    let (Some(obj_a), Some(obj_b)) = (obj_a, obj_b) else {
1460→        return if rng.random_bool(0.5) {
1461→            (a.clone(), b.clone())
1462→        } else {
1463→            (b.clone(), a.clone())
1464→        };
1465→    };
1466→
1467→    let mut c1 = serde_json::Map::new();
1468→    let mut c2 = serde_json::Map::new();
1469→
1470→    for (name, _typ) in fields {
1471→        let val_a = obj_a.get(name);
1472→        let val_b = obj_b.get(name);
1473→        match (val_a, val_b) {
1474→            (Some(va), Some(vb)) => {
1475→                if rng.random_bool(0.5) {
1476→                    c1.insert(name.clone(), va.clone());
1477→                    c2.insert(name.clone(), vb.clone());
1478→                } else {
1479→                    c1.insert(name.clone(), vb.clone());
1480→                    c2.insert(name.clone(), va.clone());
1481→                }
1482→            }
1483→            (Some(v), None) | (None, Some(v)) => {
1484→                // Only one parent has the field — give to one child
1485→                if rng.random_bool(0.5) {
1486→                    c1.insert(name.clone(), v.clone());
1487→                } else {
1488→                    c2.insert(name.clone(), v.clone());
1489→                }
1490→            }
1491→            (None, None) => {}
1492→        }
1493→    }
1494→
1495→    (Value::Object(c1), Value::Object(c2))
1496→}
1497→
1498→/// Single-point crossover for arrays: pick a crossover point, swap tails.
1499→fn crossover_array(a: &Value, b: &Value, rng: &mut impl Rng) -> (Value, Value) {
1500→    let arr_a = a.as_array();
1501→    let arr_b = b.as_array();
1502→
1503→    let (Some(arr_a), Some(arr_b)) = (arr_a, arr_b) else {
1504→        return if rng.random_bool(0.5) {
1505→            (a.clone(), b.clone())
1506→        } else {
1507→            (b.clone(), a.clone())
1508→        };
1509→    };
1510→
1511→    if arr_a.is_empty() && arr_b.is_empty() {
1512→        return (json!([]), json!([]));
1513→    }
1514→
1515→    // Crossover point chosen from 0..=min_len so both sides contribute
1516→    let min_len = arr_a.len().min(arr_b.len());
1517→    let point = rng.random_range(0..=min_len);
1518→
1519→    // child1 = arr_a[..point] ++ arr_b[point..]
1520→    // child2 = arr_b[..point] ++ arr_a[point..]
1521→    let mut c1: Vec<Value> = arr_a.iter().take(point).cloned().collect();
1522→    c1.extend(arr_b.iter().skip(point).cloned());
1523→
1524→    let mut c2: Vec<Value> = arr_b.iter().take(point).cloned().collect();
1525→    c2.extend(arr_a.iter().skip(point).cloned());
1526→
1527→    (json!(c1), json!(c2))
1528→}
1529→
1530→/// String-level crossover: combines characters from both parents rather than
1531→/// picking one whole string or the other. Three strategies chosen uniformly:
1532→/// splice (prefix A + suffix B), substring insertion, and single-point swap.
1533→fn crossover_string(a: &Value, b: &Value, rng: &mut impl Rng) -> (Value, Value) {
1534→    let (Some(sa), Some(sb)) = (a.as_str(), b.as_str()) else {
1535→        return if rng.random_bool(0.5) {
1536→            (a.clone(), b.clone())
1537→        } else {
1538→            (b.clone(), a.clone())
1539→        };
1540→    };
1541→
1542→    // Empty strings — fall back to uniform swap
1543→    if sa.is_empty() || sb.is_empty() {
1544→        return if rng.random_bool(0.5) {
1545→            (a.clone(), b.clone())
1546→        } else {
1547→            (b.clone(), a.clone())
1548→        };
1549→    }
1550→
1551→    let chars_a: Vec<char> = sa.chars().collect();
1552→    let chars_b: Vec<char> = sb.chars().collect();
1553→
1554→    let strategy = rng.random_range(0..STRING_CROSSOVER_STRATEGY_COUNT);
1555→    match strategy {
1556→        // Splice: prefix of A + suffix of B (and vice versa)
1557→        0 => {
1558→            let min_len = chars_a.len().min(chars_b.len());
1559→            let point = rng.random_range(0..=min_len);
1560→            let c1: String = chars_a[..point].iter().chain(&chars_b[point..]).collect();
1561→            let c2: String = chars_b[..point].iter().chain(&chars_a[point..]).collect();
1562→            (json!(c1), json!(c2))
1563→        }
1564→        // Substring insertion: random substring of B inserted into random position of A
1565→        1 => {
1566→            let start_b = rng.random_range(0..chars_b.len());
1567→            let end_b = rng.random_range(start_b..=chars_b.len());
1568→            let substr: String = chars_b[start_b..end_b].iter().collect();
1569→            let pos_a = rng.random_range(0..=chars_a.len());
1570→            let c1: String = chars_a[..pos_a]
1571→                .iter()
1572→                .chain(substr.chars().collect::<Vec<_>>().iter())
1573→                .chain(&chars_a[pos_a..])
1574→                .collect();
1575→
1576→            let start_a = rng.random_range(0..chars_a.len());
1577→            let end_a = rng.random_range(start_a..=chars_a.len());
1578→            let substr2: String = chars_a[start_a..end_a].iter().collect();
1579→            let pos_b = rng.random_range(0..=chars_b.len());
1580→            let c2: String = chars_b[..pos_b]
1581→                .iter()
1582→                .chain(substr2.chars().collect::<Vec<_>>().iter())
1583→                .chain(&chars_b[pos_b..])
1584→                .collect();
1585→
1586→            (json!(c1), json!(c2))
1587→        }
1588→        // Single-point: independent split points, swap tails
1589→        _ => {
1590→            let pa = rng.random_range(0..=chars_a.len());
1591→            let pb = rng.random_range(0..=chars_b.len());
1592→            let c1: String = chars_a[..pa].iter().chain(&chars_b[pb..]).collect();
1593→            let c2: String = chars_b[..pb].iter().chain(&chars_a[pa..]).collect();
1594→            (json!(c1), json!(c2))
1595→        }
1596→    }
1597→}
