1602→
1603→/// Produce progressively simpler variants of `value` consistent with `type_info`.
1604→///
1605→/// Returns candidates ordered roughly from "most simplified" to "least simplified".
1606→/// Never includes the original value. Used for minimal witness shrinking and
1607→/// boundary refinement — the inverse of mutation.
1608→pub fn shrink_candidates(value: &Value, type_info: &TypeInfo) -> Vec<Value> {
1609→    let candidates = match type_info {
1610→        TypeInfo::Int => shrink_int(value),
1611→        TypeInfo::Float => shrink_float(value),
1612→        TypeInfo::Str => shrink_str(value),
1613→        TypeInfo::Bool => shrink_bool(value),
1614→        TypeInfo::Array { element } => shrink_array(value, element),
1615→        TypeInfo::Object { fields } => shrink_object(value, fields),
1616→        TypeInfo::Nullable { inner } => shrink_nullable(value, inner),
1617→        TypeInfo::Union { variants } => shrink_union(value, variants),
1618→        TypeInfo::Complex { .. } | TypeInfo::Opaque { .. } | TypeInfo::Unknown => Vec::new(),
1619→    };
1620→    // Filter out duplicates and any candidate that equals the original.
1621→    let mut seen = Vec::with_capacity(candidates.len());
1622→    for c in candidates {
1623→        if c != *value && !seen.contains(&c) {
1624→            seen.push(c);
1625→        }
1626→    }
1627→    seen
1628→}
1629→
1630→fn shrink_int(value: &Value) -> Vec<Value> {
1631→    let n = match value.as_i64() {
1632→        Some(n) => n,
1633→        None => return Vec::new(),
1634→    };
1635→    let mut out = Vec::with_capacity(4);
1636→    let half = n / 2;
1637→    if half != n {
1638→        out.push(json!(half));
1639→    }
1640→    if n != 0 {
1641→        out.push(json!(0));
1642→    }
1643→    if n != 1 {
1644→        out.push(json!(1));
1645→    }
1646→    if n != -1 {
1647→        out.push(json!(-1));
1648→    }
1649→    out
1650→}
1651→
1652→fn shrink_float(value: &Value) -> Vec<Value> {
1653→    let n = match value.as_f64() {
1654→        Some(n) if n.is_finite() => n,
1655→        // NaN / Infinity / non-float → shrink to 0.0
1656→        Some(_) => return vec![json!(0.0)],
1657→        None => return Vec::new(),
1658→    };
1659→    let mut out = Vec::with_capacity(4);
1660→    let half = n / 2.0;
1661→    if (half - n).abs() > f64::EPSILON {
1662→        out.push(json!(half));
1663→    }
1664→    if n.abs() > f64::EPSILON {
1665→        out.push(json!(0.0));
1666→    }
1667→    if (n - 1.0).abs() > f64::EPSILON {
1668→        out.push(json!(1.0));
1669→    }
1670→    if (n + 1.0).abs() > f64::EPSILON {
1671→        out.push(json!(-1.0));
1672→    }
1673→    out
1674→}
1675→
1676→fn shrink_str(value: &Value) -> Vec<Value> {
1677→    let s = match value.as_str() {
1678→        Some(s) => s,
1679→        None => return Vec::new(),
1680→    };
1681→    if s.is_empty() {
1682→        return Vec::new();
1683→    }
1684→    let chars: Vec<char> = s.chars().collect();
1685→    let mut out = Vec::with_capacity(4);
1686→    // Remove last char
1687→    if chars.len() > 1 {
1688→        let without_last: String = chars[..chars.len() - 1].iter().collect();
1689→        out.push(json!(without_last));
1690→    }
1691→    // Remove first char
1692→    if chars.len() > 1 {
1693→        let without_first: String = chars[1..].iter().collect();
1694→        out.push(json!(without_first));
1695→    }
1696→    // Empty string
1697→    out.push(json!(""));
1698→    // Single first char
1699→    if chars.len() > 1 {
1700→        out.push(json!(chars[0].to_string()));
1701→    }

1608→pub fn shrink_candidates(value: &Value, type_info: &TypeInfo) -> Vec<Value> {
1609→    let candidates = match type_info {
1610→        TypeInfo::Int => shrink_int(value),
1611→        TypeInfo::Float => shrink_float(value),
1612→        TypeInfo::Str => shrink_str(value),
1613→        TypeInfo::Bool => shrink_bool(value),
1614→        TypeInfo::Array { element } => shrink_array(value, element),
1615→        TypeInfo::Object { fields } => shrink_object(value, fields),
1616→        TypeInfo::Nullable { inner } => shrink_nullable(value, inner),
1617→        TypeInfo::Union { variants } => shrink_union(value, variants),
1618→        TypeInfo::Complex { .. } | TypeInfo::Opaque { .. } | TypeInfo::Unknown => Vec::new(),
1619→    };
1620→    // Filter out duplicates and any candidate that equals the original.
1621→    let mut seen = Vec::with_capacity(candidates.len());
1622→    for c in candidates {
1623→        if c != *value && !seen.contains(&c) {
1624→            seen.push(c);
1625→        }
1626→    }
1627→    seen
1628→}
