1793→use crate::boundary_dict::get_boundary_values;
1794→use crate::protocol::LiteralValue;
1795→use crate::types::ParamInfo;
1796→
1797→/// Convert extracted literal values from static analysis into candidate input vectors.
1798→///
1799→/// For each `LiteralValue`, produces one input vector per parameter whose type
1800→/// is compatible with the literal's type. Other parameters receive a neutral default
1801→/// (first boundary value for their type).
1802→///
1803→/// Deduplication: identical `(literal, param_index)` pairs produce a single vector.
1804→pub fn literals_to_candidate_inputs(
1805→    params: &[ParamInfo],
1806→    literals: &[LiteralValue],
1807→) -> Vec<Vec<Value>> {
1808→    if params.is_empty() || literals.is_empty() {
1809→        return Vec::new();
1810→    }
1811→
1812→    // Neutral default per parameter: first boundary value or null
1813→    let defaults: Vec<Value> = params
1814→        .iter()
1815→        .map(|p| {
1816→            get_boundary_values(&p.typ)
1817→                .into_iter()
1818→                .next()
1819→                .map(|e| e.value)
1820→                .unwrap_or(Value::Null)
1821→        })
1822→        .collect();
1823→
1824→    // Deduplicate literals first
1825→    let mut lit_seen = std::collections::HashSet::new();
1826→    let deduped: Vec<&LiteralValue> = literals
1827→        .iter()
1828→        .filter(|lit| {
1829→            let key = serde_json::to_string(lit).unwrap_or_default();
1830→            lit_seen.insert(key)
1831→        })
1832→        .collect();
1833→
1834→    // Deduplicate by (param_index, serialized_value)
1835→    let mut seen = std::collections::HashSet::new();
1836→    let mut result = Vec::new();
1837→
1838→    for lit in &deduped {
1839→        for (idx, param) in params.iter().enumerate() {
1840→            let Some(val) = literal_matches_type(lit, &param.typ) else {
1841→                continue;
1842→            };
1843→            let dedup_key = (idx, serde_json::to_string(&val).unwrap_or_default());
1844→            if !seen.insert(dedup_key) {
1845→                continue;
1846→            }
1847→            let mut row = defaults.clone();
1848→            row[idx] = val;
1849→            result.push(row);
1850→        }
1851→    }
1852→
1853→    result
1854→}
1855→
1856→/// Convert interesting pool values into candidate input vectors.
1857→///
1858→/// Follows the same pattern as [`literals_to_candidate_inputs`]: for each
1859→/// parameter, looks up pool values matching that parameter's type. Each match
1860→/// produces one input vector with the pool value at that position and boundary
1861→/// defaults at other positions. Deduplicates by `(param_index, serialized_value)`.
1862→pub fn pool_to_candidate_inputs(
1863→    params: &[ParamInfo],
1864→    pool: &crate::interesting_pool::InterestingPool,
1865→) -> Vec<Vec<Value>> {
1866→    if params.is_empty() {
1867→        return Vec::new();
1868→    }
1869→
1870→    let defaults: Vec<Value> = params
1871→        .iter()
1872→        .map(|p| {
1873→            get_boundary_values(&p.typ)
1874→                .into_iter()
1875→                .next()
1876→                .map(|e| e.value)
1877→                .unwrap_or(Value::Null)
1878→        })
1879→        .collect();
1880→
1881→    let mut seen = std::collections::HashSet::new();
1882→    let mut result = Vec::new();
1883→
1884→    for (idx, param) in params.iter().enumerate() {
1885→        for val in pool.values_for_type(&param.typ) {
1886→            let dedup_key = (idx, serde_json::to_string(&val).unwrap_or_default());
1887→            if !seen.insert(dedup_key) {
1888→                continue;
1889→            }
1890→            let mut row = defaults.clone();
1891→            row[idx] = val;
1892→            result.push(row);
1893→        }
1894→    }
1895→
1896→    result
1897→}
