220→/// Split on a structural delimiter, then duplicate a random segment.
221→///
222→/// "a.b.c" → "a.b.b.c" — useful for triggering length checks, off-by-one
223→/// errors in parsers, and unexpected repetition.
224→pub fn mutate_duplicate_segment(s: &str, rng: &mut impl Rng) -> String {
225→    if let Some((delim, segments)) = split_on_best_delimiter(s) {
226→        if segments.is_empty() {
227→            return s.to_string();
228→        }
229→        let mut segments = segments;
230→        let idx = rng.random_range(0..segments.len());
231→        let dup = segments[idx].to_string();
232→        segments.insert(idx + 1, dup);
233→        segments.join(&delim.to_string())
234→    } else {
235→        s.to_string()
236→    }
237→}
